@@ -1552,6 +1552,10 @@ func cleanupMoleculeOnHandoff() {
 		fmt.Fprintf(os.Stderr, "handoff: warning: detach molecule audit failed: %v\n", err)
 	}

+	// Close all descendant wisps first, then the molecule root.
+	// Without this, handoff leaks orphan wisps into the DB.
+	forceCloseDescendants(b, molID)
+
 	// Force-close the molecule root wisp
 	if err := b.ForceCloseWithReason("handoff", molID); err != nil {
 		fmt.Fprintf(os.Stderr, "handoff: warning: couldn't close molecule %s: %v\n", molID, err)

@@ -92,6 +92,10 @@ func runPatrolReport(cmd *cobra.Command, args []string) error {
 		style.PrintWarning("could not update patrol summary: %v", err)
 	}

+	// Close all descendant wisps first (recursive), then the patrol root.
+	// Without this, every patrol cycle leaks ~10 orphan wisps into the DB.
+	forceCloseDescendants(b, patrolID)
+
 	// Close the patrol root
 	if err := b.ForceCloseWithReason("patrol cycle complete: "+patrolReportSummary, patrolID); err != nil {
 		return fmt.Errorf("closing patrol %s: %w", patrolID, err)

@@ -181,7 +181,10 @@ func burnExistingMolecules(molecules []string, beadID, townRoot string) error {
 		}
 	}

-	// Step 4: Force-close the orphaned wisp roots so they don't linger.
+	// Step 4: Close descendants, then force-close the orphaned wisp roots.
+	for _, molID := range molecules {
+		forceCloseDescendants(bd, molID)
+	}
 	if err := bd.ForceCloseWithReason("burned: force re-sling", molecules...); err != nil {
 		fmt.Printf("  %s Could not close molecule wisp(s): %v\n",
 			style.Dim.Render("Warning:"), err)
